import{_ as o,o as a,c as t,a2 as d}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"공통코드 관리 화면 lego 이식 — Research (Phase 0)","description":"","frontmatter":{"title":"공통코드 관리 화면 lego 이식 — Research (Phase 0)","feature_id":"016","created":"2026-06-10 20:30 (KST)","date":"2026-06-10T00:00:00.000Z","tags":["research","frontend","code","lego-parity"]},"headers":[],"relativePath":"specs/016-code-management-parity/research.md","filePath":"specs/016-code-management-parity/research.md","lastUpdated":null}'),c={name:"specs/016-code-management-parity/research.md"};function l(r,e,i,s,n,u){return a(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="research-공통코드-관리-화면-lego-이식" tabindex="-1">Research: 공통코드 관리 화면 lego 이식 <a class="header-anchor" href="#research-공통코드-관리-화면-lego-이식" aria-label="Permalink to &quot;Research: 공통코드 관리 화면 lego 이식&quot;">​</a></h1><p>spec 016 은 차단 <code>NEEDS CLARIFICATION</code> 이 없다(정합 깊이·CodeSelect·cascade 경고 모두 clarify 에서 확정). Phase 0 은 <strong>현행 코드베이스 대조</strong>로 설계 결정을 고정한다.</p><h2 id="d1-정합-깊이-—-프론트만-이식-백엔드-재사용" tabindex="-1">D1. 정합 깊이 — 프론트만 이식, 백엔드 재사용 <a class="header-anchor" href="#d1-정합-깊이-—-프론트만-이식-백엔드-재사용" aria-label="Permalink to &quot;D1. 정합 깊이 — 프론트만 이식, 백엔드 재사용&quot;">​</a></h2><ul><li><strong>Decision</strong>: 백엔드 <code>/api/v1/codes</code>(feature 004)를 무변경으로 사용하고 화면만 추가한다.</li><li><strong>Rationale</strong>: 동일 도메인 백엔드가 이미 존재(<code>CodeController</code>/<code>CodeService</code>/<code>CodeMapper</code>, 그룹·항목 CRUD, ADMIN 통제, <code>@Cacheable</code> 캐시). 시드(USER_STATUS 그룹 + 3항목)도 있어 화면 연결 즉시 동작. spec 결정 = &quot;프론트만 이식&quot;.</li><li><strong>Alternatives</strong>: 백엔드 필드를 lego(<code>codeName</code>·<code>attr1/2/3</code>)에 맞춰 정렬(015식 B) → 기존 API/데이터 회귀 위험·작업량 증가 대비 이득 없음 → 기각.</li></ul><h2 id="d2-필드-매핑-—-현행-백엔드-dto-기준" tabindex="-1">D2. 필드 매핑 — 현행 백엔드 DTO 기준 <a class="header-anchor" href="#d2-필드-매핑-—-현행-백엔드-dto-기준" aria-label="Permalink to &quot;D2. 필드 매핑 — 현행 백엔드 DTO 기준&quot;">​</a></h2><ul><li><strong>Decision</strong>: 화면·타입은 현행 <code>CodeDtos</code> 필드명을 따른다. <ul><li>그룹: <code>groupCode·groupName·description·useYn</code>.</li><li>항목: <code>groupCode·codeValue·codeLabel·sortOrder·extra1·extra2·useYn</code>.</li></ul></li><li><strong>Rationale</strong>: lego 는 <code>codeName</code>/<code>attr1·2·3</code>(3개)이나 현행은 <code>codeLabel</code>/<code>extra1·2</code>(2개). 백엔드가 단일 출처이므로 화면이 백엔드에 맞춘다. 확장속성은 2개만 노출.</li><li><strong>Alternatives</strong>: lego 명칭 유지 후 매핑 레이어 → 불필요한 변환·혼동 → 기각.</li></ul><h2 id="d3-ui-컴포넌트-관례-—-v-table-v-dialog-폼-native-confirm" tabindex="-1">D3. UI 컴포넌트 관례 — v-table + v-dialog 폼 + native confirm <a class="header-anchor" href="#d3-ui-컴포넌트-관례-—-v-table-v-dialog-폼-native-confirm" aria-label="Permalink to &quot;D3. UI 컴포넌트 관례 — v-table + v-dialog 폼 + native confirm&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>DeptsView.vue</code> 관례를 따른다 — 목록 <code>v-card</code>+<code>v-table</code>, 추가/수정 <code>v-dialog</code> 폼, 삭제 native <code>confirm</code>, 저장/삭제 후 <code>uiStore.pushToast</code> + 재로드.</li><li><strong>Rationale</strong>: 현행 관리 화면 일관성(시각·상호작용). lego 의 <code>v-data-table</code>/삭제 v-dialog 는 본 저장소에 미사용 → 관례 충돌 회피. cascade 경고는 <code>confirm</code> 문구로 충분히 표현 가능.</li><li><strong>Alternatives</strong>: lego 의 <code>v-data-table</code> 도입 → 다른 관리 화면과 이질 → 기각.</li></ul><h2 id="d4-오류·중복키-처리-—-인터셉터-자동-토스트" tabindex="-1">D4. 오류·중복키 처리 — 인터셉터 자동 토스트 <a class="header-anchor" href="#d4-오류·중복키-처리-—-인터셉터-자동-토스트" aria-label="Permalink to &quot;D4. 오류·중복키 처리 — 인터셉터 자동 토스트&quot;">​</a></h2><ul><li><strong>Decision</strong>: 별도 오류 처리 없이 <code>client.ts</code> 응답 인터셉터에 위임.</li><li><strong>Rationale</strong>: 백엔드가 중복 그룹코드/코드값에 <code>CONFLICT</code> + 한국어 메시지(&quot;이미 존재하는 코드 그룹/값입니다.&quot;)를 반환하고, 인터셉터가 <code>error.response.data.message</code> 를 토스트한다. 화면은 성공 경로만 작성하면 된다(<code>api/depts.ts</code> 동일 패턴).</li><li><strong>Alternatives</strong>: 폼 인라인 검증으로 중복 선검사 → 서버 권위 중복·왕복 추가 → 기각.</li></ul><h2 id="d5-네비게이션-진입점-—-appshell-하드코딩" tabindex="-1">D5. 네비게이션 진입점 — AppShell 하드코딩 <a class="header-anchor" href="#d5-네비게이션-진입점-—-appshell-하드코딩" aria-label="Permalink to &quot;D5. 네비게이션 진입점 — AppShell 하드코딩&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>AppShell.vue</code> 관리 섹션에 &quot;공통코드&quot; 항목을 하드코딩으로 추가 (<code>to=&quot;/admin/codes&quot;</code>, <code>requiresAdmin</code> 가드). <code>titleMap</code> 에 페이지 타이틀 추가.</li><li><strong>Rationale</strong>: 현행 관리 네비(사용자·역할·부서·메뉴·메뉴권한)가 모두 하드코딩. <code>/admin/codes</code> SYS_MENU 시드는 없음(grep 확인) → 동적 메뉴로는 안 뜸. 형제와 동일 방식이 가장 일관적이고 시드 변경(백엔드 무변경 원칙)도 피함.</li><li><strong>Alternatives</strong>: SYS_MENU 시드 추가로 동적 노출 → 백엔드/시드 변경 유발 → 보류(범위 밖).</li></ul><h2 id="d6-codeselect-재사용-컴포넌트" tabindex="-1">D6. CodeSelect 재사용 컴포넌트 <a class="header-anchor" href="#d6-codeselect-재사용-컴포넌트" aria-label="Permalink to &quot;D6. CodeSelect 재사용 컴포넌트&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>props.groupCode</code> 로 항목 로드, <code>useYn===&#39;Y&#39;</code> 만 노출, <code>v-model</code> 양방향, <code>item-title=&quot;codeLabel&quot;</code>·<code>item-value=&quot;codeValue&quot;</code>.</li><li><strong>Rationale</strong>: lego <code>CodeSelect.vue</code> 의 핵심 계약을 현행 api/타입으로 적응. 본 기능에서 소비처를 강제하지 않되(현 폼들은 자체 select 사용), 재사용 가능한 단위로 제공 + 단위테스트.</li><li><strong>Alternatives</strong>: 전역 코드 캐시 스토어 도입 → 과설계, 범위 밖 → 기각(컴포넌트 내 로드로 충분).</li></ul><h2 id="미해결-사항" tabindex="-1">미해결 사항 <a class="header-anchor" href="#미해결-사항" aria-label="Permalink to &quot;미해결 사항&quot;">​</a></h2><p>없음 — 모든 설계 결정 고정. data-model·contracts·quickstart 로 진행.</p>',16)])])}const p=o(c,[["render",l]]);export{h as __pageData,p as default};
